// Java 25 exam prep - Generics wildcard copy
// Learn: read from ? extends and write into a concrete destination.
import java.util.ArrayList;
import java.util.List;

static void copyScores(List<? extends Number> source, List<Number> target) {
  // addAll can read Number values from any Number subtype list.
  target.addAll(source);
}

List<Integer> rawScores = List.of(7, 8, 9);
List<Number> reportScores = new ArrayList<>();
copyScores(rawScores, reportScores);
reportScores.add(10.5);
